SELECT r.*, p.name product_name, u.name user_name, COALESCE(rc.report_count, 0) AS report_count FROM reviews r JOIN products p ON r.product_id = p.product_id JOIN users u ON r.user_id = u.user_id LEFT JOIN ( SELECT target_id, COUNT(*) AS report_count FROM reports WHERE target_type = 'REVIEW' GROUP BY target_id ) rc ON rc.target_id = r.review_id
AND r.user_id = #{user_id}
AND r.product_id = #{product_id}
AND r.review_id = #{review_id}
AND r.rating = #{rating}
AND r.status = UPPER(#{status})
AND ( p.name LIKE CONCAT("%", #{keyword}, "%") OR u.name LIKE CONCAT("%", #{keyword}, "%") OR r.content LIKE CONCAT("%", #{keyword}, "%") )
AND r.created_at >= CONCAT(#{startDate}, ' 00:00:00')
AND r.created_at <= CONCAT(#{endDate}, ' 23:59:59')
ORDER BY r.created_at ASC, r.review_id ASC
ORDER BY r.rating DESC, r.review_id DESC
ORDER BY report_count DESC, r.review_id DESC
ORDER BY r.created_at DESC, r.review_id DESC
LIMIT #{size} OFFSET #{offset}

SELECT count(*)
FROM reviews r
JOIN products p ON r.product_id = p.product_id
JOIN users u ON r.user_id = u.user_id


